import { GoogleGenAI, FunctionDeclaration, Type, GenerateContentResponse, Content, Part } from "@google/genai";
import { TOOLS } from '../constants';
import { UserProfile, NewsItem } from '../types';

const getSystemInstruction = (profile?: UserProfile) => {
  let instruction = `
You are Personal CA, a Senior Chartered Accountant AI.
Exclusively follow Indian Finance Act 2024 and Budget 2024.
Rules:
- 12.5% LTCG, 20% STCG.
- Indexation removed for property after 2001.
- Provide professional tables for numerical data.
- Brief explanations before tool activations.
`;

  if (profile) {
    instruction += `
USER: ${profile.name}
LIQUIDITY: ₹${profile.monthlyIncome.toLocaleString()} pm
TRACKS: ${profile.complianceTracks.join(', ')}
BANK: ${profile.memoryBank || "N/A"}
`;
  }
  return instruction;
};

const activateToolDeclaration: FunctionDeclaration = {
  name: 'activate_tool',
  description: 'Initializes a specific statutory calculator.',
  parameters: {
    type: Type.OBJECT,
    properties: {
      toolId: { type: Type.STRING, enum: TOOLS.map(t => t.id) },
      initialData: { type: Type.STRING, description: 'JSON string of data.' }
    },
    required: ['toolId']
  }
};

const draftDocumentDeclaration: FunctionDeclaration = {
  name: 'draft_document',
  description: 'Generates a formal legal or tax document.',
  parameters: {
    type: Type.OBJECT,
    properties: {
      title: { type: Type.STRING },
      content: { type: Type.STRING },
      type: { type: Type.STRING, enum: ['Legal', 'Tax', 'Corporate', 'Audit', 'Strategic'] }
    },
    required: ['title', 'content', 'type']
  }
};

let chatHistory: Content[] = [];

export const initializeGemini = (profile?: UserProfile, history?: Content[]) => {
  chatHistory = history || [];
};

export const resetChatSession = (profile?: UserProfile) => {
  chatHistory = [];
};

export const clearChatSession = () => {
  chatHistory = [];
};

export const sendMessageToGemini = async (
  message: string, 
  onToolCall: (toolId: string, data: any) => void,
  onDraftCall: (title: string, content: string, type: string) => void,
  profile?: UserProfile,
  onStream?: (text: string, sources?: {uri: string, title: string}[]) => void,
  attachments?: { data: string, mimeType: string }[]
): Promise<{text: string, sources: {uri: string, title: string}[]}> => {

  if (!process.env.API_KEY) throw new Error("API KEY MISSING");
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const currentParts: Part[] = [{ text: message }];
  if (attachments) {
    attachments.forEach(file => currentParts.push({ inlineData: { data: file.data, mimeType: file.mimeType } }));
  }

  const currentContent: Content = { role: 'user', parts: currentParts };

  try {
    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: [...chatHistory, currentContent],
      config: {
        systemInstruction: getSystemInstruction(profile),
        tools: [{ functionDeclarations: [activateToolDeclaration, draftDocumentDeclaration] }]
      }
    });

    let fullText = '';
    let sources: {uri: string, title: string}[] = [];
    let toolCalls: any[] = [];

    for await (const chunk of responseStream) {
      const response = chunk as GenerateContentResponse;
      const text = response.text;

      const groundingMetadata = response.candidates?.[0]?.groundingMetadata;
      if (groundingMetadata?.groundingChunks) {
        groundingMetadata.groundingChunks.forEach((c: any) => {
          if (c.web && !sources.find(s => s.uri === c.web.uri)) {
            sources.push({ uri: c.web.uri, title: c.web.title });
          }
        });
      }

      if (text) {
        fullText += text;
        if (onStream) onStream(fullText, sources);
      }

      if (response.functionCalls) {
        toolCalls.push(...response.functionCalls);
      }
    }

    if (toolCalls.length > 0) {
      for (const call of toolCalls) {
        if (call.name === 'activate_tool') {
          let parsedData = {};
          try { if(call.args.initialData) parsedData = JSON.parse(call.args.initialData as string); } catch(e) {}
          onToolCall(call.args.toolId as string, parsedData);
        } else if (call.name === 'draft_document') {
          onDraftCall(call.args.title as string, call.args.content as string, call.args.type as string);
        }
      }
    }

    const finalResultText = fullText || "Module initialized.";
    chatHistory.push(currentContent, { role: 'model', parts: [{ text: finalResultText }] });

    return { text: finalResultText, sources };
  } catch (error: any) {
    console.error("Gemini Critical Error", error);
    throw error;
  }
};

export const transcribeAudio = async (base64Audio: string, mimeType: string): Promise<string> => {
  if (!process.env.API_KEY) return "";
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ parts: [{ inlineData: { data: base64Audio, mimeType } }, { text: "Transcribe financial query." }] }]
    });
    return response.text || "";
  } catch (e) { return ""; }
};

export const fetchRealTimeIntel = async (): Promise<NewsItem[]> => {
  if (!process.env.API_KEY) return [];
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: "Latest 4 Indian statutory updates (GST, IT). Return JSON array: [{id, title, category, date, summary, impactLevel}]. Code block only.",
      config: { tools: [{ googleSearch: {} }] }
    });

    const jsonMatch = (response.text || "").match(/```json\s*([\s\S]*?)\s*```/);
    if (jsonMatch) return JSON.parse(jsonMatch[1]);
    return [];
  } catch (e) { return []; }
};

import React, { useMemo, useState, useRef, useEffect } from 'react';
import { X, FileText, Download, Printer, Sparkles, ChevronDown } from 'lucide-react';
import { marked } from 'marked';
import { DraftDocument } from '../types';

interface Props {
  draft: DraftDocument;
  onClose: () => void;
  isFullscreen?: boolean;
  onToggleFullscreen?: () => void;
}

const DocumentCanvas: React.FC<Props> = ({ draft, onClose }) => {
  const [showExportMenu, setShowExportMenu] = useState(false);
  const exportMenuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClick = (e: MouseEvent) => {
      if (exportMenuRef.current && !exportMenuRef.current.contains(e.target as Node)) setShowExportMenu(false);
    };
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, []);

  const htmlContent = useMemo(() => {
    if (!draft?.content) return '';
    marked.setOptions({ gfm: true, breaks: true });
    return marked.parse(draft.content);
  }, [draft?.content]);

  const handlePrint = () => {
    setShowExportMenu(false);
    setTimeout(() => window.print(), 100);
  };

  const handleExportWord = () => {
    if (!draft) return;
    const blob = new Blob([draft.content], { type: 'application/msword' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${draft.title.replace(/\s+/g, '_')}.doc`;
    link.click();
    URL.revokeObjectURL(url);
    setShowExportMenu(false);
  };

  if (!draft) return null;

  return (
    <div className="h-full flex flex-col bg-white dark:bg-black border-l border-slate-100 dark:border-white/5 animate-fade-in relative z-50">
      <div className="h-[72px] flex items-center justify-between px-6 border-b border-slate-50 dark:border-white/5 bg-white/80 dark:bg-black/80 backdrop-blur-xl shrink-0">
        <div className="flex items-center gap-3 truncate">
           <div className="w-10 h-10 rounded-xl bg-brand-500/10 text-brand-500 flex items-center justify-center shrink-0 border border-brand-500/20"><FileText size={22} /></div>
           <div className="min-w-0">
             <h2 className="text-sm font-bold text-slate-900 dark:text-white truncate uppercase tracking-tight">{draft.title}</h2>
             <span className="text-[9px] font-black text-brand-500 uppercase tracking-widest flex items-center gap-1"><Sparkles size={8}/> Validated</span>
           </div>
        </div>

        <div className="flex items-center gap-3 shrink-0">
          <div className="relative" ref={exportMenuRef}>
            <button onClick={() => setShowExportMenu(!showExportMenu)} className="h-9 px-4 rounded-xl bg-slate-100 dark:bg-white text-slate-900 dark:text-black flex items-center gap-2 text-[10px] font-black uppercase tracking-widest transition-all">
              Export <ChevronDown size={14} className={showExportMenu ? 'rotate-180' : ''} />
            </button>
            {showExportMenu && (
              <div className="absolute right-0 mt-2 w-48 bg-white dark:bg-[#1a1a1a] border border-slate-100 dark:border-white/10 rounded-2xl shadow-2xl p-2 z-[70] animate-scale-in">
                <button onClick={handleExportWord} className="w-full flex items-center gap-3 p-3 rounded-xl hover:bg-slate-50 dark:hover:bg-white/5 text-left text-[10px] font-bold uppercase tracking-widest"><Download size={14}/> Word</button>
                <button onClick={handlePrint} className="w-full flex items-center gap-3 p-3 rounded-xl hover:bg-slate-50 dark:hover:bg-white/5 text-left text-[10px] font-bold uppercase tracking-widest"><Printer size={14}/> Print</button>
              </div>
            )}
          </div>
          <button onClick={onClose} className="w-9 h-9 flex items-center justify-center rounded-xl bg-slate-100 dark:bg-[#1a1111] text-slate-400 dark:text-rose-500 hover:text-rose-600 transition-all"><X size={20}/></button>
        </div>
      </div>

