const MAX_FILES = 5;
const MAX_TOTAL_SIZE_MB = 15;

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(() => authAPI.getSession());
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isStreaming, setIsStreaming] = useState(false);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [showTools, setShowTools] = useState(false);
  const [showNews, setShowNews] = useState(false);
  const [showProfile, setShowProfile] = useState(false);
  const [showHistory, setShowHistory] = useState(window.innerWidth > 1024); 
  const [showSubscription, setShowSubscription] = useState(false);
  const [showGuidedLearning, setShowGuidedLearning] = useState(false);
  const [showQuickActions, setShowQuickActions] = useState(false);
  const [activeDraft, setActiveDraft] = useState<DraftDocument | null>(null);
  const [isDraftFullscreen, setIsDraftFullscreen] = useState(false);
  const [currentView, setCurrentView] = useState<AppView>('chat');
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [fileError, setFileError] = useState<string | null>(null);
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    const saved = localStorage.getItem('theme') as 'light' | 'dark';
    return saved || (window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light');
  });

  const [activeToolId, setActiveToolId] = useState<string | null>(null);
  const [toolData, setToolData] = useState<any>({});
  const [isRecording, setIsRecording] = useState(false);

  const [hasStarted, setHasStarted] = useState(false);
  const chatContainerRef = useRef<HTMLDivElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const quickActionsRef = useRef<HTMLDivElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const currentModelMsgIdRef = useRef<string | null>(null);

  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth > 1024 && !activeDraft) setShowHistory(true);
      else if (activeDraft) setShowHistory(false);
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [activeDraft]);

  useEffect(() => {
    if (currentUser?.profile.currentSessionId) {
      const session = currentUser.profile.chatSessions.find(s => s.id === currentUser.profile.currentSessionId);
      if (session) {
        setMessages(session.messages);
        setHasStarted(session.messages.length > 0);
        const geminiHistory: Content[] = session.messages.map(m => ({
          role: m.role === 'model' ? 'model' : 'user',
          parts: [{ text: m.content }]
        }));
        initializeGemini(currentUser.profile, geminiHistory);
      }
    }
  }, [currentUser?.profile.currentSessionId]);

  useEffect(() => {
    document.documentElement.classList.toggle('dark', theme === 'dark');
    localStorage.setItem('theme', theme);
  }, [theme]);

  const scrollToBottom = useCallback(() => {
    if (chatContainerRef.current) {
      const { scrollHeight, clientHeight } = chatContainerRef.current;
      chatContainerRef.current.scrollTo({ top: scrollHeight - clientHeight, behavior: 'smooth' });
    }
  }, []);

  useEffect(() => {
    if (isStreaming || isLoading) {
      const timer = setTimeout(scrollToBottom, 50);
      return () => clearTimeout(timer);
    }
  }, [messages, isStreaming, isLoading, scrollToBottom]);

  const handleLogin = (account: UserAccount) => {
    setCurrentUser(account);
    const sessionId = account.profile.currentSessionId;
    if (sessionId) {
       const session = account.profile.chatSessions.find(s => s.id === sessionId);
       if (session) {
          setMessages(session.messages);
          setHasStarted(session.messages.length > 0);
          resetChatSession(account.profile);
          return;
       }
    }
    setMessages([]);
    setHasStarted(false);
  };

  const handleLogout = async () => {
    await authAPI.logout();
    clearChatSession();
    setCurrentUser(null);
    setMessages([]);
    setHasStarted(false);
    setShowProfile(false);
    setActiveDraft(null);
  };

  const updateProfile = useCallback(async (newProfile: UserProfile) => {
    if (!currentUser) return;
    setCurrentUser(prev => prev ? { ...prev, profile: newProfile } : null);
    try { 
      await userAPI.updateProfile(currentUser.id, newProfile); 
    } catch (err) {
      console.error("Profile Sync Error", err);
    }
  }, [currentUser?.id]);

  const toggleTheme = () => setTheme(prev => prev === 'light' ? 'dark' : 'light');

  const handleToolCall = (toolId: string, data: any) => {
    setActiveToolId(toolId);
    setToolData(data);
    setShowTools(true);
  };

  const handleDraftCall = (title: string, content: string, type: string) => {
    const draftId = `draft_${Date.now()}`;
    const newDraft: DraftDocument = { id: draftId, title, content, type, lastUpdated: new Date() };
    setActiveDraft(newDraft);
    if (window.innerWidth < 1280) setShowHistory(false);
    if (currentModelMsgIdRef.current) {
      setMessages(prev => prev.map(m => m.id === currentModelMsgIdRef.current ? { ...m, draft: newDraft } : m));
    }
    if (currentUser) {
      const existingDrafts = currentUser.profile.drafts || [];
      updateProfile({ ...currentUser.profile, drafts: [newDraft, ...existingDrafts].slice(0, 50) });
    }
  };

  const createNewSession = () => {
    if (!currentUser) return;
    const newId = `session_${Date.now()}`;
    const newSession: ChatSession = { id: newId, title: 'New Consultation', messages: [], createdAt: new Date(), lastUpdated: new Date() };
    updateProfile({ ...currentUser.profile, chatSessions: [newSession, ...currentUser.profile.chatSessions], currentSessionId: newId });
    setMessages([]); setHasStarted(true); setActiveDraft(null);
    resetChatSession(currentUser.profile);
    if (window.innerWidth < 1024) setShowHistory(false);
  };

  const switchSession = (sessionId: string) => {
    if (!currentUser) return;
    const session = currentUser.profile.chatSessions.find(s => s.id === sessionId);
    if (session) {
      updateProfile({ ...currentUser.profile, currentSessionId: sessionId });
      setMessages(session.messages);
      setHasStarted(session.messages.length > 0);
      setCurrentView('chat');
      if (window.innerWidth < 1024) setShowHistory(false);
      setActiveDraft(null);
      const geminiHistory: Content[] = session.messages.map(m => ({
        role: m.role === 'model' ? 'model' : 'user',
        parts: [{ text: m.content }]
      }));
      initializeGemini(currentUser.profile, geminiHistory); 
    }
  };

  // Fix: Implemented optimizePrompt to refine user input for better Gemini results
  const optimizePrompt = async () => {
    if (!input.trim() || !currentUser || isOptimizing) return;
    setIsOptimizing(true);
    try {
      const response = await sendMessageToGemini(
        `Refine the following financial/tax query for clarity and professional depth. Output ONLY the improved prompt: "${input}"`,
        () => {}, // Tool call not needed for prompt refinement
        () => {}, // Draft call not needed
        currentUser.profile
      );
      if (response.text) {
        setInput(response.text.replace(/^["']|["']$/g, '').trim());
      }
    } catch (err) {
      console.error("Prompt optimization failed", err);
    } finally {
      setIsOptimizing(false);
    }
  };

  const handleSend = async (textOverride?: string) => {
    const textToSend = textOverride !== undefined ? textOverride : input;
    if (!textToSend.trim() && selectedFiles.length === 0) return;
    if (!currentUser) return;

    const sub = currentUser.profile.subscription || { tier: 'free', messageCount: 0 };
    if (sub.tier === 'free' && sub.messageCount >= 10) { setShowSubscription(true); return; }

    let nextProfile = { ...currentUser.profile };
    let sessionId = nextProfile.currentSessionId;
    nextProfile.subscription = { ...nextProfile.subscription, messageCount: nextProfile.subscription.messageCount + 1 };

    if (!sessionId) {
      sessionId = `session_${Date.now()}`;
      const newSession: ChatSession = { id: sessionId, title: textToSend.slice(0, 30), messages: [], createdAt: new Date(), lastUpdated: new Date() };
      nextProfile.chatSessions = [newSession, ...nextProfile.chatSessions];
      nextProfile.currentSessionId = sessionId;
    }

    if (!hasStarted) setHasStarted(true);
    if (currentView !== 'chat') setCurrentView('chat');

    const attachmentMetadata = selectedFiles.map(f => ({ name: f.name, type: f.type }));
    const userMsg: Message = { 
      id: `u_${Date.now()}`, 
      role: 'user', 
      content: secureSanitize(textToSend), 
      timestamp: new Date(),
      attachments: attachmentMetadata.length > 0 ? attachmentMetadata : undefined
    };

    const modelMsgId = `m_${Date.now()}`;
    currentModelMsgIdRef.current = modelMsgId;
    const placeholderMsg: Message = { id: modelMsgId, role: 'model', content: '', timestamp: new Date(), groundingSources: [] };

    setMessages(prev => [...prev, userMsg, placeholderMsg]);

    const attachments: { data: string, mimeType: string }[] = [];
    for (const file of selectedFiles) {
      const base64 = await new Promise<string>((resolve) => {
        const reader = new FileReader();
        reader.onload = () => resolve((reader.result as string).split(',')[1]);
        reader.readAsDataURL(file);
      });
      attachments.push({ data: base64, mimeType: file.type });
    }

    setInput('');
    setSelectedFiles([]);
    setIsLoading(true); setIsStreaming(true);

    try {
      const finalResponse = await sendMessageToGemini(
        textToSend, 
        handleToolCall,
        handleDraftCall,
        nextProfile,
        (streamedText, sources) => {
          setIsLoading(false);
          setMessages(prev => prev.map(m => m.id === modelMsgId ? { ...m, content: streamedText, groundingSources: sources } : m));
        },
        attachments
      );

      const finalModelMsg: Message = { 
        ...placeholderMsg, 
        content: finalResponse.text, 
        groundingSources: finalResponse.sources, 
        timestamp: new Date()
      };

      const updatedHistorySessions = nextProfile.chatSessions.map(s => {
        if (s.id === sessionId) {
          return { ...s, messages: [...s.messages, userMsg, finalModelMsg], title: s.title === 'New Consultation' ? userMsg.content.slice(0, 30) : s.title, lastUpdated: new Date() };
        }
        return s;
      });
      nextProfile.chatSessions = updatedHistorySessions;
      await updateProfile(nextProfile); 
    } catch (error) {
      setMessages(prev => prev.map(m => m.id === modelMsgId ? { ...m, content: "⚠️ System connection interrupted. Please check your network and retry.", isError: true } : m));
    } finally { 
      setIsLoading(false); 
      setIsStreaming(false); 
      currentModelMsgIdRef.current = null;
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      if ((input.trim() || selectedFiles.length > 0) && !isStreaming) handleSend();
    }
  };

  const onFilesSelected = (e: React.ChangeEvent<HTMLInputElement>) => {
    // Fix: Explicitly cast Array.from result to File[] to avoid 'unknown' type issues
    const files = Array.from(e.target.files || []) as File[];
    const validFiles = files.filter(f => ['image/jpeg', 'image/png', 'application/pdf', 'text/plain', 'text/csv'].includes(f.type));
    if (validFiles.length !== files.length) setFileError("Some formats were restricted.");
    const totalSize = [...selectedFiles, ...validFiles].reduce((acc, f) => acc + f.size, 0) / (1024 * 1024);
    if (totalSize > MAX_TOTAL_SIZE_MB) {
      setFileError("Total payload too large.");
      return;
    }
    setSelectedFiles(prev => [...prev, ...validFiles].slice(0, MAX_FILES));
    if (fileInputRef.current) fileInputRef.current.value = '';
    setTimeout(() => setFileError(null), 3000);
  };

  if (!currentUser) return <AuthScreen onLogin={handleLogin} />;

  return (
    <div className="flex h-[100dvh] font-sans text-slate-800 dark:text-slate-200 relative bg-slate-50/30 dark:bg-black overflow-hidden transition-colors">
      <aside className={`fixed inset-y-0 left-0 z-50 bg-white/95 dark:bg-[#0a0a0a] transform transition-all duration-500 ease-out border-r border-slate-100 dark:border-white/5 backdrop-blur-xl flex flex-col ${showHistory ? 'translate-x-0 w-72 lg:relative opacity-100 shadow-2xl lg:shadow-none' : '-translate-x-full w-0 lg:w-0 opacity-0 pointer-events-none'}`}>
        <div className="flex-1 flex flex-col w-72 overflow-hidden">
          <div className="h-[72px] px-6 border-b border-slate-50 dark:border-slate-850 flex items-center justify-between shrink-0">
            <div className="flex items-center gap-2.5 cursor-pointer" onClick={() => setHasStarted(false)}>
              <Logo size={28} />
              <h2 className="font-display font-bold text-slate-900 dark:text-white uppercase tracking-tight text-sm">Personal CA</h2>
            </div>
            <button onClick={() => setShowHistory(false)} className="p-2 text-slate-400 hover:text-slate-900 dark:hover:text-white transition-colors lg:hidden">
               <PanelLeftClose size={20} />
            </button>
          </div>
          <div className="p-4">
            <button onClick={createNewSession} className="w-full flex items-center justify-center gap-2 bg-white dark:bg-slate-800 dark:text-white text-slate-900 py-3 rounded-xl font-display font-bold text-xs uppercase tracking-widest hover:bg-slate-50 dark:hover:bg-slate-750 transition-all shadow-md border border-slate-200 dark:border-slate-700 active:scale-[0.98]">
              <Plus size={16} /> New Consultation
            </button>
          </div>
          <div className="flex-1 overflow-y-auto px-3 space-y-1 custom-scrollbar pb-10">
            <h3 className="px-3 mb-2 text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-[0.2em]">History</h3>
            {[...currentUser.profile.chatSessions].sort((a,b) => b.lastUpdated.getTime() - a.lastUpdated.getTime()).map((session) => (
              <button key={session.id} onClick={() => switchSession(session.id)} className={`w-full group flex flex-col p-3 rounded-xl text-left transition-all ${currentUser.profile.currentSessionId === session.id ? 'bg-slate-100/80 dark:bg-white/5' : 'hover:bg-slate-50 dark:hover:bg-white/5'}`}>
                <span className={`text-xs font-bold truncate pr-6 ${currentUser.profile.currentSessionId === session.id ? 'text-slate-900 dark:text-white' : 'text-slate-500'}`}> {session.title} </span>
                <span className="text-[9px] font-bold text-slate-400 mt-1 uppercase"> {session.lastUpdated.toLocaleDateString()} </span>
              </button>
            ))}
          </div>
          <div className="p-4 bg-slate-50/50 dark:bg-black/50 border-t border-slate-100 dark:border-white/5">
             <button onClick={() => setShowProfile(true)} className="w-full group flex items-center gap-3 p-2.5 rounded-xl hover:bg-slate-100 dark:hover:bg-white/5 transition-all text-left">
                <div className="w-9 h-9 rounded-full bg-slate-200 dark:bg-slate-800 flex items-center justify-center text-slate-500 overflow-hidden">
                   {currentUser.profile.avatarUrl ? <img src={currentUser.profile.avatarUrl} className="w-full h-full object-cover" /> : <Logo size={20} />}
                </div>
                <div className="truncate">
                  <p className="text-[11px] font-bold text-slate-900 dark:text-white truncate">{currentUser.name}</p>
                  <p className="text-[9px] font-bold text-slate-400 uppercase">Profile Settings</p>
                </div>
             </button>
          </div>
        </div>
      </aside>

      <main className={`flex flex-col relative min-w-0 transition-all duration-500 h-full ${activeDraft ? (isDraftFullscreen ? 'md:w-[320px]' : 'md:w-1/2') : 'flex-1'}`}>
          <header className={`fixed top-0 left-0 right-0 z-30 h-[72px] transition-all duration-500 ${showHistory ? 'lg:left-72' : 'lg:left-0'} ${hasStarted ? 'bg-white/80 dark:bg-[#050505]/80 backdrop-blur-xl border-b border-slate-100 dark:border-white/5' : ''}`}>
            <div className="h-full w-full flex items-center justify-between px-6">
              <div className="flex items-center gap-3">
                {!showHistory && <button onClick={() => setShowHistory(true)} className="p-2 -ml-2 rounded-lg text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors"><PanelLeft size={20} /></button>}
                <div className="flex items-center gap-2"><Logo size={28} /><h1 className="text-xs font-display font-bold text-slate-900 dark:text-white uppercase tracking-widest hidden sm:block">Personal CA</h1></div>
              </div>
              <div className="flex items-center gap-2">
                {hasStarted && (
                  <div className="flex bg-slate-100 dark:bg-white/5 p-1 rounded-xl border border-slate-200 dark:border-white/5">
                    <button onClick={() => setCurrentView('chat')} className={`px-4 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${currentView === 'chat' ? 'bg-white dark:bg-slate-800 shadow-sm text-slate-900 dark:text-white' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}>Chat</button>
                    <button onClick={() => setCurrentView('dashboard')} className={`px-4 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${currentView === 'dashboard' ? 'bg-white dark:bg-slate-800 shadow-sm text-slate-900 dark:text-white' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}>Dash</button>
                  </div>
                )}
                <div className="flex items-center gap-1.5">
                  <button onClick={() => setShowTools(true)} className="h-9 w-9 flex items-center justify-center rounded-xl bg-white dark:bg-white/5 border border-slate-200 dark:border-white/10 text-slate-600 dark:text-slate-300 hover:bg-slate-50 transition-all"><LayoutGrid size={16} /></button>
                  <button onClick={() => setShowNews(true)} className="h-9 w-9 flex items-center justify-center rounded-xl bg-white dark:bg-white/5 border border-slate-200 dark:border-white/10 text-slate-600 dark:text-slate-300 hover:bg-slate-50 transition-all"><Bell size={16} /></button>
                </div>
              </div>
            </div>
          </header>

          <div className="flex-1 w-full max-w-4xl mx-auto overflow-hidden flex flex-col pt-[72px]">
              {!hasStarted ? (
                <div className="flex-1 flex flex-col items-center justify-center px-6 animate-fade-in pb-12">
                   <div className="mb-8 relative"><div className="absolute inset-0 bg-brand-400/20 rounded-full blur-3xl scale-150"></div><Logo size={96} className="relative z-10 animate-float shadow-2xl rounded-3xl" /></div>
                   <h2 className="text-3xl md:text-5xl font-display font-bold text-slate-900 dark:text-white mb-2 text-center tracking-tight">Financial Intelligence</h2>
                   <p className="text-slate-500 dark:text-slate-400 text-center max-w-md mb-10 text-base">Indian Budget 2024 compliant advisory engine.</p>
                   <button onClick={() => setHasStarted(true)} className="flex items-center gap-2 bg-slate-900 dark:bg-white dark:text-black px-7 py-3 rounded-2xl font-display font-bold hover:opacity-90 shadow-lg uppercase tracking-widest text-xs transition-all">Start Consult <ChevronRight size={16} /></button>
                </div>
              ) : (
                <div className="flex-1 flex flex-col overflow-hidden px-4 md:px-0">
                   {currentView === 'chat' ? (
                     <div ref={chatContainerRef} className="flex-1 overflow-y-auto space-y-10 py-6 pb-48 custom-scrollbar scroll-smooth">
                        {messages.length === 0 ? (
                          <div className="h-full flex flex-col items-center justify-center text-center space-y-8 animate-fade-in">
                            <h2 className="text-2xl font-display font-bold text-slate-900 dark:text-white">What can I compute for you?</h2>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-3 w-full max-w-2xl px-4">
                              {SUGGESTIONS.map((s, i) => (
                                <button key={i} onClick={() => handleSend(s.prompt)} className="p-4 bg-white dark:bg-[#0a0a0a] border border-slate-200 dark:border-white/5 rounded-2xl text-left hover:border-brand-300 transition-all group">
                                  <h4 className="font-display font-bold text-slate-800 dark:text-slate-100 text-sm group-hover:text-brand-600">{s.title}</h4>
                                  <p className="text-xs text-slate-500 dark:text-slate-400 line-clamp-2 mt-1">{s.description}</p>
                                </button>
                              ))}
                            </div>
                          </div>
                        ) : (
                          messages.map((msg, idx) => (
                              <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'} animate-slide-up`}>
                                {msg.role === 'user' ? (
                                  <div className="bg-slate-100 dark:bg-slate-800 text-slate-900 dark:text-white px-4 py-3 rounded-2xl rounded-tr-md shadow-sm text-sm border border-slate-200 dark:border-white/5 max-w-[85%] break-words">{msg.content}</div>
                                ) : (
                                  <div className="w-full flex gap-3">
                                    <div className="w-8 h-8 flex-shrink-0 mt-1"><Logo size={22} animate={idx === messages.length - 1 && isLoading && !msg.content} /></div>
                                    <div className="flex-1 max-w-[95%]">
                                       <div className={`p-1 rounded-2xl ${msg.isError ? 'bg-rose-50 dark:bg-rose-900/10 border border-rose-100 dark:border-rose-900/20' : ''}`}>
                                          {idx === messages.length - 1 && isLoading && !msg.content ? <ThinkingDots /> : <TypingText text={msg.content} isStreaming={isStreaming} isLast={idx === messages.length - 1} />}
                                          {msg.draft && (
                                            <div className="mt-4 p-4 bg-slate-100/50 dark:bg-white/[0.03] border border-slate-200 dark:border-white/5 rounded-2xl flex justify-between items-center group/draft">
                                              <div className="flex items-center gap-3"><FileSearch size={20} className="text-brand-500"/><h4 className="text-sm font-bold truncate pr-2">{msg.draft.title}</h4></div>
                                              <button onClick={() => setActiveDraft(msg.draft!)} className="px-4 py-2 bg-brand-500 text-white rounded-lg text-[10px] font-black uppercase tracking-wider hover:opacity-90 transition-all">Open</button>
                                            </div>
                                          )}
                                       </div>
                                    </div>
                                  </div>
                                )}
                              </div>
                          ))
                        )}
                     </div>
                   ) : (
                     <div className="flex-1 overflow-y-auto custom-scrollbar pb-20"><FinancialDashboard profile={currentUser.profile} onLaunchTool={handleToolCall} /></div>
                   )}
                </div>
              )}

              {hasStarted && currentView === 'chat' && (
                <div className="absolute bottom-0 left-0 right-0 z-20 px-4 pb-8 pt-4 bg-gradient-to-t from-white via-white/90 to-transparent dark:from-black dark:via-black/90 dark:to-transparent">
                   <div className="w-full max-w-2xl mx-auto space-y-4">
                      {selectedFiles.length > 0 && (
                        <div className="flex flex-wrap gap-2 px-2 animate-fade-in">
                          {selectedFiles.map((file, idx) => (
                            <div key={idx} className="flex items-center gap-2 px-3 py-1 bg-white dark:bg-slate-900 border border-slate-200 dark:border-white/10 rounded-full shadow-sm text-[10px] font-bold">
                               <FileImage size={12} className="text-brand-500" />
                               <span className="truncate max-w-[100px]">{file.name}</span>
                               <button onClick={() => setSelectedFiles(prev => prev.filter((_, i) => i !== idx))}><X size={10} /></button>
                            </div>
                          ))}
                        </div>
                      )}
                      <div className="bg-slate-100 dark:bg-[#121212] rounded-[28px] p-2 flex items-center gap-2 border border-slate-200 dark:border-white/5 shadow-xl transition-all focus-within:ring-2 focus-within:ring-brand-500/10">
                          <button onClick={() => fileInputRef.current?.click()} className="w-11 h-11 flex items-center justify-center rounded-full text-slate-500 hover:text-brand-500 transition-all"><Plus size={22}/></button>
                          <input type="file" ref={fileInputRef} className="hidden" multiple onChange={onFilesSelected} />
                          <textarea 
                             ref={textareaRef} 
                             rows={1} 
                             value={input} 
                             onChange={(e) => setInput(e.target.value)} 
                             onKeyDown={handleKeyDown} 
                             disabled={isStreaming} 
                             placeholder=""
                             className="flex-1 bg-transparent border-none focus:ring-0 resize-none py-3.5 max-h-[150px] text-sm text-slate-900 dark:text-slate-100 z-10 font-medium" 
                          />
                          {!input && <AnimatedPlaceholder />}
                          <button onClick={() => handleSend()} disabled={!input.trim() && selectedFiles.length === 0 || isStreaming} className={`w-11 h-11 rounded-full flex items-center justify-center transition-all ${input.trim() || selectedFiles.length > 0 ? 'bg-slate-900 dark:bg-white text-white dark:text-black shadow-lg' : 'bg-slate-200 dark:bg-white/5 text-slate-300 dark:text-slate-700 cursor-not-allowed'}`}>
                            {isStreaming ? <Square size={14} fill="currentColor" /> : <Send size={20} />}
                          </button>
                      </div>
                      <div className="flex justify-center gap-2">
                        <button onClick={() => setShowQuickActions(!showQuickActions)} className="px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest bg-white dark:bg-slate-800 border border-slate-200 dark:border-white/5 shadow-sm hover:scale-105 transition-all">Strategic Tools</button>
                        <button onClick={optimizePrompt} disabled={!input.trim() || isOptimizing} className="px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest bg-amber-50 dark:bg-amber-900/20 text-amber-600 dark:text-amber-400 border border-amber-200/50 dark:border-amber-900/50 shadow-sm hover:scale-105 transition-all disabled:opacity-50">Refine Prompt</button>
                      </div>
                   </div>
                </div>
              )}
          </div>
      </main>

      {activeDraft && (
        <div className={`fixed inset-0 z-50 md:relative md:z-auto animate-slide-up h-full ${isDraftFullscreen ? 'md:w-[calc(100%-320px)]' : 'md:w-1/2'}`}>
           <DocumentCanvas draft={activeDraft} onClose={() => { setActiveDraft(null); setIsDraftFullscreen(false); }} isFullscreen={isDraftFullscreen} onToggleFullscreen={() => setIsDraftFullscreen(!isDraftFullscreen)} />
        </div>
      )}

      <ToolsPanel isOpen={showTools} activeToolId={activeToolId} onClose={() => setShowTools(false)} onSelectTool={setActiveToolId} toolData={toolData} profile={currentUser.profile} onUpdateProfile={updateProfile} />
      <NewsPanel isOpen={showNews} onClose={() => setShowNews(false)} profile={currentUser.profile} onAskAboutNews={(news) => handleSend(`Tell me more about: ${news}`)} />
      <ProfilePanel isOpen={showProfile} onClose={() => setShowProfile(false)} profile={currentUser.profile} onUpdate={updateProfile} theme={theme} onToggleTheme={toggleTheme} onLogout={handleLogout} />
      <SubscriptionModal isOpen={showSubscription} onClose={() => setShowSubscription(false)} profile={currentUser.profile} onUpgrade={(tier) => {
        if (currentUser) updateProfile({ ...currentUser.profile, subscription: { ...currentUser.profile.subscription, tier } });
        setShowSubscription(false);
      }} />
      <GuidedLearningOverlay isOpen={showGuidedLearning} onClose={() => setShowGuidedLearning(false)} onSelectPath={(prompt) => handleSend(prompt)} />
    </div>
  );
};

export default App;
